s/No":"-","Link to relevant Proof":[{"name":"SeminarConfFDPOrganised.pdf","fileName":"SeminarConfFDPOrganised.pdf","url":"https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/05af65b4cd70cb50/attachments/55464a22-05a4-4f2a-9ce4-17846cff0d65-SeminarConfFDPOrganised.pdf"}]}],"fdpAttended":[{"Sl. No":"1","Name of Faculty":"All faculty","Title of seminar/course":"-","Sponsoring Agency / organization":"-","Duration with dates":"-","Date":"","Link to relevant Proof":[{"name":"SeminarConfFDPAttended.pdf","fileName":"SeminarConfFDPAttended.pdf","url":"https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/05af65b4cd70cb50/attachments/471bbe78-eeb9-4758-9593-558f37307f68-SeminarConfFDPAttended.pdf"}]}],"functionalMous":[{"Sr No":"1","Name of the Organization / Institution / Industry with whom MoU is signed":"All Active MoUs","Year of signing MoU":"-","Duration of MoU":"-","List the actual activities under each MoU":"-","Link to relevant Proof":[{"name":"FunctionalMoUs.pdf","fileName":"FunctionalMoUs.pdf","url":"https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/05af65b4cd70cb50/attachments/f7f967ea-61d0-4736-b3dd-76ac63413837-FunctionalMoUs.pdf"},{"name":"FunctionalMoUs.pdf","fileName":"FunctionalMoUs.pdf","url":"https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/05af65b4cd70cb50/attachments/a72553cb-9bcb-485a-865f-b0fb2e3380f9-FunctionalMoUs.pdf"}]}],"swocStrength":[{"Sr No":"1","Details":"1.\\tFaculty members hold PhDs from reputed Indian and international institutions with expertise in disciplines like biotechnology, bioinformatics, criminology, food technology, bioprocess engineering, biomaterial science etc.  2.\\tThe school offers Multidisciplinary programs in emerging areas such as Bioengineering, Forensic Science, Medical Biotechnology, and Medicinal Chemistry 3.\\tActive research culture with research proposals being submitted to national funding agencies 4.\\tWell-equipped laboratories for UG and PG programmes 5.\\tCurriculum aligned with NEP 2020 and industry needs 6.\\tInterdisciplinary approach encouraged through electives and research 7.\\tThe school Organizes national conferences, workshops, FDPs, and student skill-development activities. 8.\\tGrowing collaborations with industry and research organizations. 9.\\tThe School is a hub bridging together ideas from technology and basic sciences with biology through teaching and research.  10. We encourage students to engage in experiential learning through projects, industry collaborations, and seminars."}],"swocWeaknesses":[{"Sr No":"1","Details":"1.\\tNeed for additional specialised faculty in cutting-edge areas like Biomedical instrumentation, Forensic science, Medicinal chemistry 2.\\tLimited infrastructure for advanced research, some sophisticated equipments like HR/MS, ICP-OES, Tangential flow filtration unit are required 3.\\tLaboratory space constraints with rising student intake 4.\\tInadequate computational biology and bioinformatics support 5.\\tNeed for increased industry collaborations, consultancy, and technology transfer activities. 6.\\tLimited number of patents, technology commercialization, and startup initiatives 7.\\tProfessional body activities, guest lectures, and certification programs can be strengthened. 8.\\tStudent participation in national-level competitions, hackathons, and innovation challenges can be increased. 9. Stronger industrial participation and more internship opportunities are required."}],"swocOpportunities":[{"Sr No":"1","Details":"1.\\tExpand collaborations with industries, hospitals, research institutes, and international universities 2.\\tOrganize regular activities under professional bodies, including expert lectures, certification courses, industrial visits, and student chapters 3.\\tEstablish Centres of Excellence in areas such as Biomanufacturing, Functional Foods, Precision Health, or Forensic Genomics 4.\\tPromote student start-ups, incubation, patent filing, and entrepreneurship through innovation ecosystems 5.\\tIncrease consultancy, testing services, and continuing education programs to generate revenue 6.\\tStrengthen alumni engagement for placements, internships, mentoring, and research collaborations 7.\\tExpansion into futuristic areas: synthetic biology, AI in biology, neurobio, etc.  8.\\tPotential to launch interdisciplinary and skill-oriented programmes. 9. Promote the value of undergraduate and graduate research in developing critical thinking, creativity, and problem-solving abilities through undergraduate and graduate students'' research and innovation societies, with the goal of promoting and supporting original research and innovation projects carried out by students under faculty mentorship."}],"swocChallenges":[{"Sr No":"1","Details":"1.\\tIntense competition from established institutions in attracting quality students and research funding 2.\\tSecuring sustained external funding in a highly competitive environment 3.\\tKeeping curriculum aligned with rapidly evolving technologies such as AI, synthetic biology, precision medicine, and digital biomanufacturing 4.\\tRetaining highly skilled faculty and researchers while balancing teaching, research, and administrative responsibilities 5.\\tTranslating laboratory research into commercially viable products and technologies. 6.\\tMaintaining high-quality infrastructure and laboratory equipment within budget constraints 7.\\tMeeting evolving accreditation, NAAC, NBA, and NIRF expectations while maintaining academic excellence. 8. Challenges in attracting a large number of recruiters for ongoing programs within the school."}],"swocOtherInformation":[{"Sr No":"1","Details":""}]}', '[{"name":"NEP Implementation.pdf","fileName":"NEP Implementation.pdf","url":"https://storage.googleapis.com/dypiu-schoolappraisal-uploads/users/05af65b4cd70cb50/attachments/dd4605b2-15cc-456b-8e3d-47951e6cd43f-NEP_Implementation.pdf"},{"name":"research articles_SoBB.pdf","fileName":"research a